SELECT T1.ID, T1.PORT_STORAGE_ID, T1.CARGO_INFO_ID, T1.WORK_DATE, T1.CLASS_CODE, T1.CLASS_NAME, T1.PROCESS_DETAIL_CODE, T1.PROCESS_DETAIL_NAME, T1.STOREHOUSE_ID, T1.STOREHOUSE_NAME, T1.REGION_ID, T1.REGION_NAME, T1.MASS_ID, T1.MASS_NAME, CASE WHEN T1.QUANTITY IS NULL THEN 0 ELSE T1.QUANTITY END QUANTITY, T1.TON, T1.INOUT_TYPE, T1.INOUT_STORAGE_CODE, T1.INOUT_STORAGE_NAME, T1.WORK_TICKET_ID, T1.WORK_TICKET_DETAIL_ID, T1.CARGO_TALLY_ID, T1.CARGO_TALLY_DETAIL_ID, T1.INOUT_DATE, CASE WHEN T2.UPDATE_BY IS NULL THEN T2.CREATE_BY ELSE T2.UPDATE_BY END CREATE_BY, CASE WHEN T2.UPDATE_BY_NAME IS NULL THEN T2.CREATE_BY_NAME ELSE T2.UPDATE_BY_NAME END CREATE_BY_NAME, CASE WHEN T2.UPDATE_TIME IS NULL THEN T2.CREATE_TIME ELSE T2.UPDATE_TIME END CREATE_TIME, T1.CREATE_BY_NAME STORAGE_CREATE_BY_NAME, T1.CREATE_TIME STORAGE_CREATE_TIME, T1.UPDATE_BY, T1.UPDATE_BY_NAME, T1.UPDATE_TIME, T1.COMPANY_ID, T1.COMPANY_NAME, T1.CLEAN_MASS_SIGN, T2.TRANSPORT_EQUIPMENT_NO, T2.CREATE_BY_NAME AS "TALLY_MAN", T2.CREATE_TIME AS "TALLY_TIME"
FROM T_PRD_PORT_STORAGE_DETAIL T1 LEFT JOIN T_YARD_TALLY T2 ON T1.CARGO_TALLY_ID = T2.ID WHERE T1.CARGO_INFO_ID = #{cargoInfoId,jdbcType=BIGINT} AND T1.STOREHOUSE_ID = #{storehouseId,jdbcType=BIGINT} AND T1.REGION_ID = #{regionId,jdbcType=BIGINT} AND T1.MASS_ID = #{massId,jdbcType=BIGINT}
AND T1.WORK_DATE >= #{beginWorkDate, jdbcType=TIMESTAMP}
AND ( T1.WORK_DATE > #{beginWorkDate, jdbcType=TIMESTAMP} OR T1.CLASS_CODE >= TO_NUMBER( #{beginClassCode, jdbcType=VARCHAR} ) )
AND T1.WORK_DATE <= #{endWorkDate, jdbcType=TIMESTAMP}
AND ( T1.WORK_DATE < #{endWorkDate, jdbcType=TIMESTAMP} OR T1.CLASS_CODE <= TO_NUMBER( #{endClassCode, jdbcType=VARCHAR} ) )
AND T1.PROCESS_DETAIL_CODE = #{processDetailCode, jdbcType=VARCHAR}
ORDER BY T1.WORK_DATE, T1.CLASS_CODE, T1.CREATE_TIME

