UPDATE T_PRD_PORT_STORAGE
SET CLEAN_MASS_SIGN    = '1',
    CLEAN_MASS_BY      = #{loginUserId, jdbcType=BIGINT},
    CLEAN_MASS_BY_NAME = #{loginUserName, jdbcType=VARCHAR},
    CLEAN_MASS_TIME    = #{now, jdbcType=TIMESTAMP}
WHERE CARGO_INFO_ID = #{cargoInfoId, jdbcType=BIGINT}
  AND STOREHOUSE_ID = #{storehouseId, jdbcType=BIGINT}
  AND REGION_ID = #{regionId, jdbcType=BIGINT}
  AND MASS_ID = #{massId, jdbcType=BIGINT}

UPDATE T_PRD_PORT_STORAGE_DETAIL
SET CLEAN_MASS_SIGN    = '1',
    CLEAN_MASS_BY      = #{loginUserId, jdbcType=BIGINT},
    CLEAN_MASS_BY_NAME = #{loginUserName, jdbcType=VARCHAR},
    CLEAN_MASS_TIME    = #{now, jdbcType=TIMESTAMP}
WHERE CARGO_INFO_ID = #{cargoInfoId, jdbcType=BIGINT}
  AND STOREHOUSE_ID = #{storehouseId, jdbcType=BIGINT}
  AND REGION_ID = #{regionId, jdbcType=BIGINT}
  AND MASS_ID = #{massId, jdbcType=BIGINT}

UPDATE T_PRD_PORT_STORAGE
SET CLEAN_MASS_SIGN    = '0',
    CLEAN_MASS_BY      = NULL,
    CLEAN_MASS_BY_NAME = NULL,
    CLEAN_MASS_TIME    = NULL
WHERE CARGO_INFO_ID = #{cargoInfoId, jdbcType=BIGINT}
  AND STOREHOUSE_ID = #{storehouseId, jdbcType=BIGINT}
  AND REGION_ID = #{regionId, jdbcType=BIGINT}
  AND MASS_ID = #{massId, jdbcType=BIGINT}

UPDATE T_PRD_PORT_STORAGE_DETAIL
SET CLEAN_MASS_SIGN    = '0',
    CLEAN_MASS_BY      = NULL,
    CLEAN_MASS_BY_NAME = NULL,
    CLEAN_MASS_TIME    = NULL
WHERE CARGO_INFO_ID = #{cargoInfoId, jdbcType=BIGINT}
  AND STOREHOUSE_ID = #{storehouseId, jdbcType=BIGINT}
  AND REGION_ID = #{regionId, jdbcType=BIGINT}
  AND MASS_ID = #{massId, jdbcType=BIGINT}

