TBCI.CARGO_OWNER_NAME,
TBCI.CARGO_CODE,
TBCI.CARGO_NAME,
MAX(TPPSD.COMPANY_NAME) COMPANY_NAME,
SUM(TPPSD.QUANTITY) QUANTITY,
SUM(TPPSD.TON) TON
